#include <bits/stdc++.h>
using namespace std;

const int N=2e4+10;

int n,l[N],r[N],ls[N<<1],s[N<<1];
map<int,int> mp;

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d",&l[i],&r[i]);
        ls[i*2-1]=l[i],ls[i*2]=r[i];
    }
    sort(ls+1,ls+n+n+1);
    int len=unique(ls+1,ls+2*n+1)-ls-1;
    for(int i=1;i<=len;i++)
        mp[ls[i]]=i;
    for(int i=1;i<=n;i++)
        s[mp[l[i]]]++,s[mp[r[i]]]--;
    int ans=0;
    for(int i=1;i<len;i++){
        s[i]+=s[i-1];
        if(s[i])
            ans+=ls[i+1]-ls[i];
    }
    printf("%d",ans);
    return 0;
}
